    92→  /**
    93→   * Creates an equivalent {@code FxVanillaOption} using currency pair, option expiry, call/put flag, strike, base
    94→   * currency notional, and underlying payment date.
    95→   * <p>
    96→   * No payment date adjustments apply.
    97→   *
    98→   * @param longShort the long/short flag of the option
    99→   * @param expiry the option expiry
   100→   * @param currencyPair the FX currency pair
   101→   * @param putCall the put/call flag of the option
   102→   * @param strike the FX strike
   103→   * @param baseNotional the base currency notional amount: should always be positive
   104→   * @param paymentDate the payment date of the underlying FX cash flows
   105→   * @return an equivalent fx vanilla option
   106→   */
   107→  public static FxVanillaOption of(
   108→      LongShort longShort,
   109→      ZonedDateTime expiry,
   110→      CurrencyPair currencyPair,
   111→      PutCall putCall,
   112→      double strike,
   113→      double baseNotional,
   114→      LocalDate paymentDate) {
   115→
   116→    return of(longShort, expiry, currencyPair, putCall, strike, baseNotional, paymentDate, null);
   117→  }
   118→
   119→  /**
   120→   * Creates an equivalent {@code FxVanillaOption} using currency pair, option expiry, call/put flag, strike, base
   121→   * currency notional, underlying payment date, and payment date adjustment.
   122→   *
   123→   * @param longShort the long/short flag of the option
   124→   * @param expiry the option expiry
   125→   * @param currencyPair the FX currency pair
   126→   * @param putCall the put/call flag of the option
   127→   * @param strike the FX strike
   128→   * @param baseNotional the base currency notional amount: should always be positive
   129→   * @param paymentDate the payment date of the underlying FX cash flows
   130→   * @param paymentDateAdjustment the adjustment to apply to the payment date
   131→   * @return an equivalent fx vanilla option
   132→   */
   133→  public static FxVanillaOption of(
   134→      LongShort longShort,
   135→      ZonedDateTime expiry,
   136→      CurrencyPair currencyPair,
   137→      PutCall putCall,
   138→      double strike,
   139→      double baseNotional,
   140→      LocalDate paymentDate,
   141→      BusinessDayAdjustment paymentDateAdjustment) {
   142→
   143→    ArgChecker.isTrue(baseNotional > 0, "Base notional must be positive");
   144→    ArgChecker.isTrue(strike > 0, "FX strike must be positive");
   145→
   146→    // for a vanilla call, will be long the base currency and short the counter currency
   147→    // for a vanilla put, will be short the base currency and long the counter currency
   148→    double baseAmount = putCall.isCall() ? baseNotional : -baseNotional;
   149→    double counterNotional = strike * baseNotional;
   150→    double counterAmount = putCall.isCall() ? -counterNotional : counterNotional;
   151→    CurrencyAmount baseCurrencyAmount = CurrencyAmount.of(currencyPair.getBase(), baseAmount);
   152→    CurrencyAmount counterCurrencyAmount = CurrencyAmount.of(currencyPair.getCounter(), counterAmount);
   153→    FxSingle equivalentUnderlying = paymentDateAdjustment == null ?
   154→        FxSingle.of(baseCurrencyAmount, counterCurrencyAmount, paymentDate) :
   155→        FxSingle.of(baseCurrencyAmount, counterCurrencyAmount, paymentDate, paymentDateAdjustment);
   156→
   157→    return FxVanillaOption.builder()
   158→        .longShort(longShort)
   159→        .expiryDate(expiry.toLocalDate())
   160→        .expiryTime(expiry.toLocalTime())
   161→        .expiryZone(expiry.getZone())
   162→        .underlying(equivalentUnderlying)
   163→        .build();
   164→  }
